/**
 * @fileoverview Accordion component definition for JIT pipeline.
 *
 * Bundles design tokens, state machine config, template slot definitions,
 * event handler abstractions, and Custom Element metadata.
 *
 * @module module/Accordion.def
 */

import razyui from '../index.js';
import { PART } from './Accordion/constants.js';

/**
 * Definition object for the Accordion component.
 * @type {object}
 */
export const AccordionDef = {
    name: 'Accordion',
    tag: 'rui-accordion',

    // ═════════════════════════════════════
    //  Design Tokens
    // ═════════════════════════════════════
    tokens: {
        prefix: 'ac',
        tokens: {
            'text':         { ref: 'color.text',       description: 'Text color' },
            'border':       { ref: 'color.border',     description: 'Item border color' },
            'bg':           { ref: 'color.bg-surface',  description: 'Panel background' },
            'bg-hover':     { ref: 'color.bg-inset',    description: 'Trigger hover background' },
            'accent':       { ref: 'color.accent',      description: 'Accent color for expanded indicator' },
            'font-size':    { ref: 'font.size-md',      description: 'Trigger font size' },
            'padding':      { value: '0.4rem 0.8rem',   description: 'Trigger padding' },
            'panel-padding':{ value: '0 1rem 1rem',     description: 'Panel content padding' },
            'gap':          { ref: 'spacing.3',         description: 'Gap between trigger text and icon' },
            'icon-size':    { value: '1rem',            description: 'Chevron icon size' },
            'icon-color':   { ref: 'color.text-muted',  description: 'Chevron icon color' },
            'radius':       { ref: 'radius.md',         description: 'Border radius' },
            'font-stack':   { ref: 'font.family',       description: 'Font family' },
        },
    },

    // ═════════════════════════════════════
    //  State Machine
    // ═════════════════════════════════════
    states: {
        initial: 'collapsed',
        states: {
            collapsed: { on: { EXPAND: 'expanded', DISABLE: 'disabled' } },
            expanded:  { on: { COLLAPSE: 'collapsed', DISABLE: 'disabled' } },
            disabled:  { on: { ENABLE_COLLAPSED: 'collapsed', ENABLE_EXPANDED: 'expanded' } },
        },
        // Effects are implemented in view.js SM_EFFECTS (DOM manipulation)
    },

    // ═════════════════════════════════════
    //  Template Slots
    // ═════════════════════════════════════
    template: {
        slots: {
            root:    { element: 'div',    classes: ['accordion'],         role: null },
            item:    { element: 'div',    classes: ['accordion-item'],    role: null },
            header:  { element: 'div',    classes: ['accordion-header'],  role: null },
            trigger: { element: 'button', classes: ['accordion-trigger'], role: 'button' },
            icon:    { element: 'span',   classes: ['accordion-icon'],    role: null },
            panel:   { element: 'div',    classes: ['accordion-panel'],   role: 'region' },
        },
    },

    // ═════════════════════════════════════
    //  JIT Parts
    // ═════════════════════════════════════
    jitParts: {
        [PART.ROOT]: PART.ROOT,
        [PART.ITEM]: PART.ITEM,
        [PART.HEADER]: PART.HEADER,
        [PART.TRIGGER]: PART.TRIGGER,
        [PART.ICON]: PART.ICON,
        [PART.PANEL]: PART.PANEL,
    },

    // ═════════════════════════════════════
    //  Inline Styles (CSS rules)
    // ═════════════════════════════════════
    styles: {},

    // ═════════════════════════════════════
    //  Event Handlers
    // ═════════════════════════════════════
    handlers: {
        trigger: {
            click(ctx, e, index) {
                e.preventDefault();
                ctx.toggle(index);
            },
            keydown(ctx, e, index) {
                const triggers = ctx.triggers;
                let targetIndex;

                switch (e.key) {
                    case ' ':
                    case 'Enter':
                        e.preventDefault();
                        ctx.toggle(index);
                        break;
                    case 'ArrowDown':
                        e.preventDefault();
                        targetIndex = ctx.findNextItem(index, 1);
                        if (targetIndex !== null) ctx.focusTrigger(targetIndex);
                        break;
                    case 'ArrowUp':
                        e.preventDefault();
                        targetIndex = ctx.findNextItem(index, -1);
                        if (targetIndex !== null) ctx.focusTrigger(targetIndex);
                        break;
                    case 'Home':
                        e.preventDefault();
                        targetIndex = ctx.findNextItem(-1, 1);
                        if (targetIndex !== null) ctx.focusTrigger(targetIndex);
                        break;
                    case 'End':
                        e.preventDefault();
                        targetIndex = ctx.findNextItem(triggers.length, -1);
                        if (targetIndex !== null) ctx.focusTrigger(targetIndex);
                        break;
                }
            },
        },
    },

    // ═════════════════════════════════════
    //  Variants
    // ═════════════════════════════════════
    variants: {},

    // ═════════════════════════════════════
    //  Custom Element
    // ═════════════════════════════════════
    observedAttrs: ['multiple', 'active-index', 'collapsible'],
    attrMap: {
        multiple:      'multiple',
        'active-index': 'activeIndex',
        collapsible:   'collapsible',
    },
};

export default AccordionDef;
