/**
 * @fileoverview Accordion state — pure state machine transitions + reactive state wiring.
 * @module module/Accordion/state
 */

/**
 * Pure state machine transition map for a single accordion item.
 * Each item independently tracks collapsed / expanded / disabled.
 */
export const ITEM_TRANSITIONS = {
    initial: 'collapsed',
    states: {
        collapsed: { on: { EXPAND: 'expanded', DISABLE: 'disabled' } },
        expanded:  { on: { COLLAPSE: 'collapsed', DISABLE: 'disabled' } },
        disabled:  { on: { ENABLE_COLLAPSED: 'collapsed', ENABLE_EXPANDED: 'expanded' } },
    },
};

/**
 * Create reactive accordion state tracking expanded indices.
 *
 * @param {Function} stateFn — `razyui.state` factory
 * @param {Array<import('../shared/StateMachine.js').StateMachine>} itemSMs — per-item state machines
 * @returns {{ ref: object, setState: Function }}
 */
export function createReactiveState(stateFn, itemSMs) {
    const stateSet = stateFn({ expandedIndices: [] });
    const ref      = stateSet[0];
    const setState = stateSet[1];

    stateSet.effect(() => {
        const indices = ref.expandedIndices;
        itemSMs.forEach((sm, i) => {
            if (sm.current === 'disabled') return;
            const isExpanded = indices.includes(i);
            const isCurrent  = sm.current === 'expanded';
            if (isExpanded && !isCurrent) sm.send('EXPAND');
            else if (!isExpanded && isCurrent) sm.send('COLLAPSE');
        });
    });

    return { ref, setState };
}
