/**
 * @fileoverview Accordion events — centralised event binding via AbortController.
 * @module module/Accordion/events
 */

import razyui from '../../index.js';
import { AccordionDef as DEF } from '../Accordion.def.js';

/**
 * Create the handler context object consumed by DEF event dispatchers.
 *
 * @param {Function} provider — () => live state
 * @returns {object} handler context with live getters
 */
export function createHandlerCtx(provider) {
    return {
        get triggers()       { return provider().triggers; },
        get expandedIndices() { return provider().expandedIndices; },
        get multiple()       { return provider().multiple; },
        toggle(index)        { provider().toggle(index); },
        focusTrigger(index)  { provider().focusTrigger(index); },
        findNextItem(from, dir) { return provider().findNextItem(from, dir); },
    };
}

/**
 * Bind click and keyboard events on the accordion root.
 * Returns an AbortController — call `.abort()` to unbind all listeners.
 *
 * @param {Elements} root — the root element
 * @param {Array<Element>} triggers — trigger elements
 * @param {object} ctx — handler context from createHandlerCtx
 * @returns {AbortController}
 */
export function bindEvents(root, triggers, ctx) {
    const ac   = new AbortController();
    const opts = { signal: ac.signal };

    triggers.forEach((trigger, index) => {
        const wr = razyui(trigger);
        wr.on('click',   e => DEF.handlers.trigger.click(ctx, e, index),   opts);
        wr.on('keydown', e => DEF.handlers.trigger.keydown(ctx, e, index), opts);
    });

    return ac;
}
