/**
 * @fileoverview Accordion component — modular entry point.
 *
 * Orchestrates sub-modules:
 *   constants.js — CSS classes, ARIA attrs, default config
 *   helpers.js   — item navigation utility
 *   state.js     — pure SM transitions + reactive state wiring
 *   view.js      — DOM setup / teardown + SM effects
 *   events.js    — centralised event binding (AbortController cleanup)
 *
 * @module module/Accordion
 */

import { default as razyui } from '../../index.js';
import { StateMachine } from '../shared/StateMachine.js';
import { AccordionDef as DEF } from '../Accordion.def.js';

import { DEFAULTS, SEL, CLS }                                  from './constants.js';
import { findNextItem }                                         from './helpers.js';
import { ITEM_TRANSITIONS, createReactiveState }                from './state.js';
import { SM_EFFECTS, setupRoot, setupItemARIA, cleanupDOM }     from './view.js';
import { createHandlerCtx, bindEvents }                         from './events.js';
import { emitEvent }                                            from '../shared/emitEvent.js';

/**
 * Accordion — expandable/collapsible panel component (JIT-compatible)
 *
 * Enhances a container with header/panel pairs into an accessible
 * accordion with keyboard navigation and animated transitions.
 *
 * Features:
 *   - Single or multiple expand mode
 *   - Collapsible (all panels can be closed)
 *   - ARIA button + region pattern
 *   - Keyboard navigation (↑ ↓ Home End Space Enter)
 *   - Disabled items
 *   - Animated expand/collapse via max-height
 *   - Callbacks: onExpand, onCollapse
 *   - Programmatic API: expand(), collapse(), toggle(), expandAll(), collapseAll(), getControl()
 *
 * @param {string|Element} selector — CSS selector or Element for the root container
 * @param {object}   [config]
 * @param {boolean}  [config.multiple=false]      — allow multiple panels open
 * @param {number|null} [config.activeIndex=null]  — initial expanded index (null = all closed)
 * @param {boolean}  [config.collapsible=true]     — allow all panels to be collapsed
 * @param {Array<number>} [config.disabled=[]]     — indices to disable
 * @param {function} [config.onExpand]             — (index) => void
 * @param {function} [config.onCollapse]           — (index) => void
 */
const Accordion = class {
    #root      = null;
    #destroyed = false;
    #items     = [];       // { item, trigger, panel, icon } per item
    #itemSMs   = [];       // per-item StateMachine instances
    #config    = {};
    #stateRef  = null;
    #setState  = null;
    #uid       = 0;
    #eventAC   = null;

    static #counter = 0;

    constructor(selector, config = {}) {
        const root = razyui(selector);

        if (!root.length) {
            console.warn('Accordion: element not found \u2192', selector);
            return;
        }

        this.#root   = root;
        this.#config = { ...DEFAULTS, ...config };
        this.#uid    = ++Accordion.#counter;

        this.#init();
    }

    #init() {
        const config = this.#config;
        const root   = this.#root;
        const uid    = this.#uid;

        // 1. View: setup root container
        setupRoot(root);

        // 2. Gather items — each item has a header (trigger) and a panel
        const itemEls = root[0].querySelectorAll(SEL.ITEM);
        const smConfig = { ...ITEM_TRANSITIONS, effects: SM_EFFECTS };

        itemEls.forEach((itemEl, i) => {
            const triggerEl = itemEl.querySelector(SEL.HEADER) || itemEl.querySelector(SEL.TRIGGER);
            const panelEl   = itemEl.querySelector(SEL.PANEL);

            if (!triggerEl || !panelEl) {
                console.warn('Accordion: item missing header or panel \u2192', i);
                return;
            }

            // 3. ARIA + DOM setup per item
            const refs = setupItemARIA(itemEl, triggerEl, panelEl, uid, i);
            this.#items.push(refs);

            // 4. Per-item state machine
            const sm = new StateMachine(smConfig, {
                trigger: refs.trigger,
                panel:   refs.panel,
                icon:    refs.icon,
                item:    refs.item,
            });

            // Handle initially disabled items
            if (config.disabled.includes(i)) {
                sm.reset('disabled');
                SM_EFFECTS.disabled({ trigger: refs.trigger, item: refs.item });
            }

            this.#itemSMs.push(sm);
        });

        // 5. Reactive state
        const { ref, setState } = createReactiveState(razyui.state, this.#itemSMs);
        this.#stateRef = ref;
        this.#setState = setState;

        // 6. Events
        const triggers = this.#items.map(it => it.trigger);
        const ctx = createHandlerCtx(() => ({
            triggers:        triggers,
            expandedIndices: this.#stateRef.expandedIndices,
            multiple:        this.#config.multiple,
            toggle:          i => this.toggle(i),
            focusTrigger:    i => triggers[i]?.focus(),
            findNextItem:    (from, dir) => findNextItem(triggers, from, dir),
        }));
        this.#eventAC = bindEvents(root, triggers, ctx);

        // 7. Initial expansion
        if (config.activeIndex !== null && config.activeIndex !== undefined) {
            const indices = Array.isArray(config.activeIndex)
                ? config.activeIndex
                : [config.activeIndex];
            const validIndices = indices.filter(i =>
                i >= 0 && i < this.#items.length && !config.disabled.includes(i)
            );
            if (validIndices.length) {
                this.#setState({ expandedIndices: config.multiple ? validIndices : [validIndices[0]] });
            }
        }
    }

    // ── Public API ──

    /** Expand a panel by index. */
    expand(index) {
        if (index < 0 || index >= this.#items.length) return;
        if (this.#itemSMs[index]?.current === 'disabled') return;

        const current = [...this.#stateRef.expandedIndices];
        if (current.includes(index)) return;

        const next = this.#config.multiple ? [...current, index] : [index];
        this.#setState({ expandedIndices: next });

        emitEvent(this.#root[0], 'expand', { index });
        if (typeof this.#config.onExpand === 'function') {
            this.#config.onExpand.call(this, index);
        }
    }

    /** Collapse a panel by index. */
    collapse(index) {
        if (index < 0 || index >= this.#items.length) return;

        const current = [...this.#stateRef.expandedIndices];
        if (!current.includes(index)) return;

        // Check collapsible — if not collapsible and this is the last open panel, don't collapse
        if (!this.#config.collapsible && current.length === 1) return;

        const next = current.filter(i => i !== index);
        this.#setState({ expandedIndices: next });

        emitEvent(this.#root[0], 'collapse', { index });
        if (typeof this.#config.onCollapse === 'function') {
            this.#config.onCollapse.call(this, index);
        }
    }

    /** Toggle a panel by index. */
    toggle(index) {
        if (this.#stateRef.expandedIndices.includes(index)) {
            this.collapse(index);
        } else {
            this.expand(index);
        }
    }

    /** Expand all non-disabled panels (only works in multiple mode). */
    expandAll() {
        if (!this.#config.multiple) return;
        const indices = this.#items
            .map((_, i) => i)
            .filter(i => this.#itemSMs[i]?.current !== 'disabled');
        this.#setState({ expandedIndices: indices });
    }

    /** Collapse all panels. */
    collapseAll() {
        if (!this.#config.collapsible) return;
        this.#setState({ expandedIndices: [] });
    }

    /** Get the current expanded indices. */
    get expandedIndices() {
        return [...this.#stateRef.expandedIndices];
    }

    /** Check if a specific index is expanded. */
    isExpanded(index) {
        return this.#stateRef.expandedIndices.includes(index);
    }

    /** Enable/disable an item by index. */
    setDisabled(index, disabled) {
        const sm = this.#itemSMs[index];
        if (!sm) return;

        if (disabled && sm.current !== 'disabled') {
            // Collapse if expanded
            if (this.#stateRef.expandedIndices.includes(index)) {
                this.collapse(index);
            }
            sm.reset('disabled');
            SM_EFFECTS.disabled({
                trigger: this.#items[index].trigger,
                item:    this.#items[index].item,
            });
        } else if (!disabled && sm.current === 'disabled') {
            sm.send('ENABLE_COLLAPSED');
        }
    }

    /**
     * Get a reactive control object with get/set properties.
     * @returns {object}
     */
    getControl() {
        const self = this;
        return {
            get expandedIndices() { return self.expandedIndices; },
            get multiple() { return self.#config.multiple; },
            set multiple(v) { self.#config.multiple = !!v; },
            get collapsible() { return self.#config.collapsible; },
            set collapsible(v) { self.#config.collapsible = !!v; },
            get activeIndex() { return self.expandedIndices; },
            set activeIndex(v) { self.expand(Number(v)); },
            expandAll:   () => self.expandAll(),
            collapseAll: () => self.collapseAll(),
            isExpanded:  i => self.isExpanded(i),
            setDisabled: (i, d) => self.setDisabled(i, d),
            destroy:     () => self.destroy(),
            get element() { return self.#root[0]; },
            get destroyed() { return self.#destroyed; },
        };
    }

    /** Cleanup — remove DOM modifications and event listeners. */
    destroy() {
        if (this.#destroyed) return;
        this.#destroyed = true;
        this.#eventAC?.abort();
        cleanupDOM(this.#root);
        this.#itemSMs = [];
        this.#items   = [];
    }
};

export default Accordion;
